include("shared.lua")local ring = Material("sgm/playercircle")function ENT:DrawTranslucent()	local ply = LocalPlayer()	if ply:IsAdmin() or ply:IsSuperAdmin() then		cam.IgnoreZ(true)		render.DrawLine(self.SpawnPos, self.SpawnPos + Vector(0, 0, -Crates.WobbleHeight * 6), color_white, true)		render.SetMaterial(ring)		self:DrawModel()		render.DrawQuadEasy(self.SpawnPos + Vector(0, 0, -Crates.WobbleHeight * 6), Vector(0, 0, 1), 20, 20, color_white)		cam.IgnoreZ(false)	endend